"use client"

import { Skeleton } from "@/components/ui/skeleton"
import { useState } from "react"
import Canvas from "./editor"
import { PdfLoader } from "./pdf-loader"
import { PdfShapes } from "./pdf-shapes"

type CanvasState =
  | { status: "empty" }
  | { status: "loading" }
  | { status: "loaded"; bytes: Uint8Array }
  | { status: "error"; message: string }

export function CanvasHost() {
  const [state, setState] = useState<CanvasState>({ status: "empty" })

  function handleFile(bytes: Uint8Array) {
    setState({ status: "loaded", bytes })
  }

  async function handleExample() {
    setState({ status: "loading" })
    try {
      const res = await fetch("/sample.pdf")
      if (!res.ok) throw new Error(`fetch failed: ${res.status}`)
      const buf = await res.arrayBuffer()
      setState({ status: "loaded", bytes: new Uint8Array(buf) })
    } catch (err) {
      setState({
        status: "error",
        message: err instanceof Error ? err.message : "Failed to load sample.",
      })
    }
  }

  function handleError(message: string) {
    setState({ status: "error", message })
  }

  if (state.status === "empty" || state.status === "error") {
    return (
      <PdfLoader
        onFile={handleFile}
        onExample={handleExample}
        onError={handleError}
        error={state.status === "error" ? state.message : undefined}
      />
    )
  }

  if (state.status === "loading") {
    return (
      <div className="flex min-h-svh items-center justify-center">
        <div className="flex w-full max-w-sm flex-col gap-3 p-8">
          <Skeleton className="h-6 w-3/4" />
          <Skeleton className="h-4 w-full" />
          <Skeleton className="h-4 w-5/6" />
          <Skeleton className="mt-4 h-64 w-full rounded-xl" />
        </div>
      </div>
    )
  }

  return (
    <Canvas>
      <PdfShapes bytes={state.bytes} onError={handleError} />
    </Canvas>
  )
}

"use client"

import { useEditor, useValue } from "tldraw"
import { cropStateAtom } from "./camera-tool"

export function CropOverlay() {
  const editor = useEditor()

  const rect = useValue(
    "cropRect",
    () => {
      const state = cropStateAtom.get()
      if (state.status !== "dragging") return null
      const s = editor.pageToScreen({ x: state.startX, y: state.startY })
      const e = editor.pageToScreen({ x: state.currentX, y: state.currentY })
      return {
        x: Math.min(s.x, e.x),
        y: Math.min(s.y, e.y),
        w: Math.abs(e.x - s.x),
        h: Math.abs(e.y - s.y),
      }
    },
    [editor]
  )

  if (!rect) return null

  return (
    <svg
      aria-hidden="true"
      style={{
        position: "absolute",
        inset: 0,
        width: "100%",
        height: "100%",
        pointerEvents: "none",
        overflow: "visible",
      }}
    >
      {/* shadow stroke for contrast */}
      <rect
        x={rect.x}
        y={rect.y}
        width={rect.w}
        height={rect.h}
        fill="rgba(0,0,0,0.1)"
        stroke="rgba(0,0,0,0.5)"
        strokeWidth={3}
        strokeDasharray="8 4"
      />
      {/* white marching-ants stroke — animation defined in globals.css */}
      <rect
        className="tl-camera-marquee"
        x={rect.x}
        y={rect.y}
        width={rect.w}
        height={rect.h}
        fill="none"
        stroke="white"
        strokeWidth={1.5}
        strokeDasharray="8 4"
      />
    </svg>
  )
}

import { toast } from "sonner"
import { Box, StateNode, atom } from "tldraw"
import type { TLKeyboardEventInfo, TLPointerEventInfo } from "tldraw"
import { exportCropImage } from "./export-image"

const MIN_CROP_SIZE = 8

type CropState =
  | { status: "idle" }
  | {
      status: "dragging"
      startX: number
      startY: number
      currentX: number
      currentY: number
    }

export const cropStateAtom = atom<CropState>("camera/cropState", {
  status: "idle",
})

export class CameraTool extends StateNode {
  static override id = "camera"

  override onEnter() {
    this.editor.setCursor({ type: "cross", rotation: 0 })
  }

  override onExit() {
    cropStateAtom.set({ status: "idle" })
    this.editor.setCursor({ type: "default", rotation: 0 })
  }

  override onPointerDown(_info: TLPointerEventInfo) {
    const { x, y } = this.editor.inputs.currentPagePoint
    cropStateAtom.set({
      status: "dragging",
      startX: x,
      startY: y,
      currentX: x,
      currentY: y,
    })
  }

  override onPointerMove(_info: TLPointerEventInfo) {
    const state = cropStateAtom.get()
    if (state.status !== "dragging") return
    const { x, y } = this.editor.inputs.currentPagePoint
    cropStateAtom.set({ ...state, currentX: x, currentY: y })
  }

  override onPointerUp(_info: TLPointerEventInfo) {
    const state = cropStateAtom.get()
    if (state.status !== "dragging") return

    const { startX, startY, currentX, currentY } = state
    cropStateAtom.set({ status: "idle" })

    const w = Math.abs(currentX - startX)
    const h = Math.abs(currentY - startY)

    if (w > MIN_CROP_SIZE && h > MIN_CROP_SIZE) {
      const bounds = Box.FromPoints([
        { x: startX, y: startY },
        { x: currentX, y: currentY },
      ])
      exportCropImage(this.editor, bounds)
      this.editor.setCurrentTool("select")
      return
    }

    // A deliberate (non-zero) drag that fell below the threshold — nudge the
    // user and stay on the camera tool so they can retry without reactivating.
    if (w > 1 || h > 1) {
      toast.info("Crop too small — drag a larger area to export")
      return
    }

    // Zero-drag click: treat as a cancel and return to select.
    this.editor.setCurrentTool("select")
  }

  override onKeyDown(info: TLKeyboardEventInfo) {
    if (info.key === "Escape") {
      cropStateAtom.set({ status: "idle" })
      this.editor.setCurrentTool("select")
    }
  }
}

"use client"

import { useEffect } from "react"
import type { Editor, TLShape, TLShapeId } from "tldraw"
import type { TLPinShape } from "./pin-shape-util"

export interface PinSnapshot {
  id: TLShapeId
  x: number
  y: number
  attachedShapeIds: readonly TLShapeId[]
}

export interface ShapeSnapshot {
  id: TLShapeId
  type: TLShape["type"]
  x: number
  y: number
}

export type ShapeMove = ShapeSnapshot

// Pure helper so we can unit-test the delta math without mounting tldraw.
// Returns the list of shape/pin moves triggered by `movedShapeId` shifting by
// (dx, dy). The moved shape itself is not included — the caller has already
// applied that move. Each affected shape (and pin) is emitted once, even when
// several pins' attached sets overlap.
export function computePinUpdates(
  pins: Iterable<PinSnapshot>,
  movedShapeId: TLShapeId,
  dx: number,
  dy: number,
  getShape: (id: TLShapeId) => ShapeSnapshot | null
): ShapeMove[] {
  const updates: ShapeMove[] = []
  const seen = new Set<TLShapeId>([movedShapeId])

  for (const pin of pins) {
    if (!pin.attachedShapeIds.includes(movedShapeId)) continue

    if (!seen.has(pin.id)) {
      seen.add(pin.id)
      updates.push({
        id: pin.id,
        type: "pin",
        x: pin.x + dx,
        y: pin.y + dy,
      })
    }

    for (const shapeId of pin.attachedShapeIds) {
      if (seen.has(shapeId)) continue
      const shape = getShape(shapeId)
      if (!shape) continue
      seen.add(shapeId)
      updates.push({
        id: shapeId,
        type: shape.type,
        x: shape.x + dx,
        y: shape.y + dy,
      })
    }
  }

  return updates
}

function snapshotOfPin(shape: TLPinShape): PinSnapshot {
  return {
    id: shape.id,
    x: shape.x,
    y: shape.y,
    attachedShapeIds: shape.props.attachedShapeIds,
  }
}

export function usePinAttachment(editor: Editor | null) {
  useEffect(() => {
    if (!editor) return

    // Per-editor propagation guard. A plain boolean isn't enough: tldraw's
    // flushAtomicCallbacks while-loop processes each round of pendingAfterEvents
    // in a new iteration, resetting handler context between rounds. When shapeA
    // moves and we propagate shapeB, shapeB's afterChange fires in the *next*
    // iteration with the boolean already reset, triggering another cascade.
    // Tracking each propagated ID lets us skip exactly those shapes later.
    const propagatedIds = new Set<TLShapeId>()

    // Pin index kept in sync via sideEffects. Avoids walking every shape on
    // the page (O(shapes)) on every shape afterChange during a drag; lookup
    // now scales with the number of pins, not total shapes on the canvas.
    const pinIndex = new Map<TLShapeId, PinSnapshot>()
    for (const shape of editor.getCurrentPageShapes()) {
      if (shape.type === "pin") {
        pinIndex.set(shape.id, snapshotOfPin(shape as TLPinShape))
      }
    }

    const disposeCreate = editor.sideEffects.registerAfterCreateHandler(
      "shape",
      (created) => {
        if (created.type !== "pin") return
        pinIndex.set(created.id, snapshotOfPin(created as TLPinShape))
      }
    )

    const disposeChange = editor.sideEffects.registerAfterChangeHandler(
      "shape",
      (prev, next) => {
        // Keep the pin index in sync on any pin change (including moves we
        // propagate ourselves — the index needs to reflect new positions).
        if (next.type === "pin") {
          pinIndex.set(next.id, snapshotOfPin(next as TLPinShape))
          return
        }

        if (propagatedIds.has(next.id)) {
          propagatedIds.delete(next.id)
          return
        }
        if (next.x === prev.x && next.y === prev.y) return

        // Skip resizes. Dragging a top/left handle also changes x/y (alongside
        // w/h in props), and we don't want to drag attached shapes along on
        // resize — only on pure translate.
        const prevW = (prev.props as { w?: number }).w
        const prevH = (prev.props as { h?: number }).h
        const nextW = (next.props as { w?: number }).w
        const nextH = (next.props as { h?: number }).h
        if (prevW !== nextW || prevH !== nextH) return

        if (pinIndex.size === 0) return

        const dx = next.x - prev.x
        const dy = next.y - prev.y

        const updates = computePinUpdates(
          pinIndex.values(),
          next.id,
          dx,
          dy,
          (id) => {
            const shape = editor.getShape(id)
            if (!shape) return null
            return { id: shape.id, type: shape.type, x: shape.x, y: shape.y }
          }
        )

        if (updates.length === 0) return

        for (const update of updates) {
          propagatedIds.add(update.id)
        }
        editor.run(() => {
          editor.updateShapes(
            updates.map((u) => ({
              id: u.id,
              type: u.type,
              x: u.x,
              y: u.y,
            }))
          )
        })
      }
    )

    const disposeDelete = editor.sideEffects.registerAfterDeleteHandler(
      "shape",
      (deleted: TLShape) => {
        if (deleted.type === "pin") {
          pinIndex.delete(deleted.id)
          return
        }

        const affected: PinSnapshot[] = []
        for (const pin of pinIndex.values()) {
          if (pin.attachedShapeIds.includes(deleted.id)) affected.push(pin)
        }
        if (affected.length === 0) return

        editor.markHistoryStoppingPoint("pin attachment cascade")
        editor.run(() => {
          const pinsToDelete: TLShapeId[] = []
          const pinsToUpdate: Array<{
            id: TLShapeId
            type: "pin"
            props: { attachedShapeIds: TLShapeId[] }
          }> = []

          for (const pin of affected) {
            const nextIds = pin.attachedShapeIds.filter(
              (id) => id !== deleted.id
            )
            if (nextIds.length < 2) {
              pinsToDelete.push(pin.id)
            } else {
              pinsToUpdate.push({
                id: pin.id,
                type: "pin",
                props: { attachedShapeIds: nextIds },
              })
            }
          }

          if (pinsToUpdate.length > 0) {
            editor.updateShapes(pinsToUpdate)
          }
          if (pinsToDelete.length > 0) {
            editor.deleteShapes(pinsToDelete)
          }
        })
      }
    )

    return () => {
      disposeCreate()
      disposeChange()
      disposeDelete()
    }
  }, [editor])
}

import {
  HTMLContainer,
  type RecordProps,
  Rectangle2d,
  ShapeUtil,
  T,
  type TLBaseShape,
  type TLShapeId,
  shapeIdValidator,
} from "tldraw"
import { PinShape } from "./pin-shape"

export type TLPinShapeProps = {
  attachedShapeIds: TLShapeId[]
}

export type TLPinShape = TLBaseShape<"pin", TLPinShapeProps>

// Augment the global shape map so `TLShape`, `editor.createShape`, and
// `editor.updateShapes` all recognise "pin" as a valid shape type.
declare module "tldraw" {
  interface TLGlobalShapePropsMap {
    pin: TLPinShapeProps
  }
}

export const PIN_WIDTH = 24
export const PIN_HEIGHT = 32

export class PinShapeUtil extends ShapeUtil<TLPinShape> {
  static override type = "pin" as const
  static override props: RecordProps<TLPinShape> = {
    attachedShapeIds: T.arrayOf(shapeIdValidator),
  }

  override canEdit = () => false
  override hideResizeHandles = () => true
  override hideRotateHandle = () => true
  override isAspectRatioLocked = () => true

  getDefaultProps(): TLPinShape["props"] {
    return { attachedShapeIds: [] }
  }

  getGeometry() {
    return new Rectangle2d({
      x: 0,
      y: 0,
      width: PIN_WIDTH,
      height: PIN_HEIGHT,
      isFilled: true,
    })
  }

  component() {
    return (
      <HTMLContainer
        style={{
          width: PIN_WIDTH,
          height: PIN_HEIGHT,
          pointerEvents: "all",
        }}
      >
        <PinShape />
      </HTMLContainer>
    )
  }

  indicator() {
    return <rect x={0} y={0} width={PIN_WIDTH} height={PIN_HEIGHT} />
  }
}

